mapper.select:
SELECT s.id, s.stocktake_no, s.stocktake_name, s.stocktake_type, CASE s.stocktake_type WHEN 1 THEN '全盘' WHEN 2 THEN '抽盘' WHEN 3 THEN '专项盘点' ELSE '未知' END AS stocktake_type_desc, s.warehouse, s.part_type, s.status, CASE s.status WHEN 0 THEN '待盘点' WHEN 1 THEN '盘点中' WHEN 2 THEN '已完成' WHEN 3 THEN '已取消' ELSE '未知' END AS status_desc, s.total_count, s.diff_count, s.profit_quantity, s.loss_quantity, s.total_amount, s.diff_amount, s.stocktake_time, s.operator_id, s.operator_name, s.complete_time, s.remark, s.create_time, s.update_time FROM spare_part_stocktake s WHERE s.deleted = 0
AND ( s.stocktake_name LIKE CONCAT('%', #{query.keyword}, '%') OR s.stocktake_no LIKE CONCAT('%', #{query.keyword}, '%') )
AND s.stocktake_type = #{query.stocktakeType}
AND s.status = #{query.status}
AND s.warehouse = #{query.warehouse}
AND s.create_time >= #{query.startTime}
AND s.create_time <= #{query.endTime}
ORDER BY s.create_time DESC
